WITH network_total AS (SELECT sum(DepDelay) as network_delay FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND Year = 2024 AND Month = 7), top_origins AS (SELECT sum(DepDelay) as origin_delay FROM (SELECT sum(DepDelay) as DepDelay FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND Year = 2024 AND Month = 7 GROUP BY OriginCode ORDER BY DepDelay DESC LIMIT 5)), top_routes AS (SELECT sum(DepDelay) as route_delay FROM (SELECT sum(DepDelay) as DepDelay FROM ontime.fact_ontime WHERE Carrier = 'AA' AND Cancelled = 0 AND Year = 2024 AND Month = 7 GROUP BY OriginCode, DestCode ORDER BY DepDelay DESC LIMIT 10)) SELECT n.network_delay, o.origin_delay as top_5_origins_delay, r.route_delay as top_10_routes_delay, round(o.origin_delay / n.network_delay * 100, 2) as top_5_origins_pct, round(r.route_delay / n.network_delay * 100, 2) as top_10_routes_pct FROM network_total n, top_origins o, top_routes r;
